import random
import time
import sys

# Clear the terminal
def clear_terminal():
    print('\033[2J\033[H', end='')

# Reaction diffusion simulator parameters
grid_size = 20
population_density = 0.5
birth_rate = 0.1
death_rate = 0.05
diffusion_rate = 0.01

# Grid to represent the reaction-diffusion system
def create_grid(size):
    grid = [[random.random() for _ in range(size)] for _ in range(size)]
    return grid

# Update the simulation step using the logistic map and reaction-diffusion equations
def update_simulation(grid, population_density, birth_rate, death_rate, diffusion_rate):
    new_grid = [[0.0 for _ in range(len(grid[0]))] for _ in range(len(grid))]
    for i in range(len(grid)):
        for j in range(len(grid[i])):
            neighbors = [grid[k][j] if k < len(grid) else 0 for k in range(i-1, i+2)]
            average_neighbors = sum(neighbors) / len(neighbors)
            new_grid[i][j] = grid[i][j] + birth_rate * (1 - grid[i][j]) * (average_neighbors - population_density)
            new_grid[i][j] += diffusion_rate * (grid[i][j] - population_density)
    return [min(max(new_value, 0.0), 1.0) for row in new_grid for new_value in row]

# Main simulation loop
