    clear_terminal()
    grid = create_grid(grid_size)
    for step in range(1, num_steps + 1):
        print(f'Step {step} - Population Density: {population_density}')
        grid = update_simulation(grid.copy(), population_density, birth_rate, death_rate, diffusion_rate)
